B.H3=new A.aZ("Hobbies","\u05ea\u05d7\u05d1\u05d9\u05d1\u05d9\u05dd")
B.Ho=new A.aZ("Yoga, audio, and books","\u05d9\u05d5\u05d2\u05d4, \u05d0\u05d5\u05d3\u05d9\u05d5 \u05d5\u05e1\u05e4\u05e8\u05d9\u05dd")
B.He=new A.aZ("I enjoy Yin yoga, long-form audio, and books that make me think. I also built an Amazon Polly and S3 text-to-speech workflow with a custom lexicon so written yoga routines could become clear audio instructions.","\u05d0\u05e0\u05d9 \u05d0\u05d5\u05d4\u05d1\u05ea \u05d9\u05d9\u05df \u05d9\u05d5\u05d2\u05d4, \u05d0\u05d5\u05d3\u05d9\u05d5 \u05d0\u05e8\u05d5\u05da \u05d5\u05e1\u05e4\u05e8\u05d9\u05dd \u05e9\u05d2\u05d5\u05e8\u05de\u05d9\u05dd \u05dc\u05d9 \u05dc\u05d7\u05e9\u05d5\u05d1. \u05d1\u05e0\u05d5\u05e1\u05e3, \u05d1\u05e0\u05d9\u05ea\u05d9 \u05ea\u05d4\u05dc\u05d9\u05da text-to-speech \u05e2\u05dd Amazon Polly \u05d5-S3, \u05db\u05d5\u05dc\u05dc \u05e7\u05d5\u05d1\u05e5 lexicon \u05de\u05d5\u05ea\u05d0\u05dd, \u05db\u05d3\u05d9 \u05dc\u05d4\u05e4\u05d5\u05da \u05e8\u05d5\u05d8\u05d9\u05e0\u05d5\u05ea \u05d9\u05d5\u05d2\u05d4 \u05db\u05ea\u05d5\u05d1\u05d5\u05ea \u05dc\u05d4\u05d5\u05e8\u05d0\u05d5\u05ea \u05d0\u05d5\u05d3\u05d9\u05d5 \u05d1\u05e8\u05d5\u05e8\u05d5\u05ea.")
B.H5=new A.aZ("Outside software work, yoga is one of the practices that helps me slow down, listen more carefully, and stay connected to the body rather than only to the screen. I especially like Yin yoga because it is quiet, patient, and precise in a different way from programming: it asks for stillness, attention, and respect for small changes over time.","\u05de\u05d7\u05d5\u05e5 \u05dc\u05e2\u05d1\u05d5\u05d3\u05d4 \u05e2\u05dd \u05ea\u05d5\u05db\u05e0\u05d4, \u05d9\u05d5\u05d2\u05d4 \u05d4\u05d9\u05d0 \u05d0\u05d7\u05ea \u05de\u05d4\u05e8\u05d5\u05d8\u05d9\u05e0\u05d5\u05ea \u05e9\u05e2\u05d5\u05d6\u05e8\u05d5\u05ea \u05dc\u05d9 \u05dc\u05d4\u05d0\u05d8, \u05dc\u05d4\u05e7\u05e9\u05d9\u05d1 \u05d8\u05d5\u05d1 \u05d9\u05d5\u05ea\u05e8 \u05d5\u05dc\u05d4\u05d9\u05e9\u05d0\u05e8 \u05de\u05d7\u05d5\u05d1\u05e8\u05ea \u05dc\u05d2\u05d5\u05e3 \u05d5\u05dc\u05d0 \u05e8\u05e7 \u05dc\u05de\u05e1\u05da. \u05d0\u05e0\u05d9 \u05d0\u05d5\u05d4\u05d1\u05ea \u05d1\u05de\u05d9\u05d5\u05d7\u05d3 \u05d9\u05d9\u05df \u05d9\u05d5\u05d2\u05d4, \u05db\u05d9 \u05d9\u05e9 \u05d1\u05d4 \u05e9\u05e7\u05d8, \u05e1\u05d1\u05dc\u05e0\u05d5\u05ea \u05d5\u05d3\u05d9\u05d5\u05e7 \u05de\u05e1\u05d5\u05d2 \u05d0\u05d7\u05e8 \u05de\u05ea\u05db\u05e0\u05d5\u05ea: \u05d4\u05d9\u05d0 \u05de\u05d1\u05e7\u05e9\u05ea \u05e9\u05d4\u05d9\u05d9\u05d4, \u05ea\u05e9\u05d5\u05de\u05ea \u05dc\u05d1 \u05d5\u05db\u05d1\u05d5\u05d3 \u05dc\u05e9\u05d9\u05e0\u05d5\u05d9\u05d9\u05dd \u05e7\u05d8\u05e0\u05d9\u05dd \u05dc\u05d0\u05d5\u05e8\u05da \u05d6\u05de\u05df.")
B.Hc=new A.aZ("That interest also led me to create a text-to-speech service for routine scripts, using Amazon Polly and S3 buckets with a custom lexicon file so the generated audio would pronounce terms naturally and turn written routines into usable spoken instructions. In the same spirit, I enjoy audiobooks, podcasts, and reading books, especially detective stories, mysteries, psychological novels, and clever classics that reward attention and layered thinking.","\u05d4\u05e2\u05e0\u05d9\u05d9\u05df \u05d4\u05d6\u05d4 \u05d1\u05e8\u05d5\u05d8\u05d9\u05e0\u05d5\u05ea \u05de\u05d5\u05e7\u05dc\u05d8\u05d5\u05ea \u05d4\u05d5\u05d1\u05d9\u05dc \u05d0\u05d5\u05ea\u05d9 \u05d2\u05dd \u05dc\u05d1\u05e0\u05d5\u05ea \u05e9\u05d9\u05e8\u05d5\u05ea text-to-speech \u05dc\u05ea\u05e1\u05e8\u05d9\u05d8\u05d9 \u05ea\u05e8\u05d2\u05d5\u05dc, \u05d1\u05d0\u05de\u05e6\u05e2\u05d5\u05ea Amazon Polly \u05d5-S3 buckets \u05d9\u05d7\u05d3 \u05e2\u05dd \u05e7\u05d5\u05d1\u05e5 lexicon \u05de\u05d5\u05ea\u05d0\u05dd, \u05db\u05d3\u05d9 \u05e9\u05d4\u05d0\u05d5\u05d3\u05d9\u05d5 \u05e9\u05e0\u05d5\u05e6\u05e8 \u05d9\u05d1\u05d8\u05d0 \u05de\u05d5\u05e0\u05d7\u05d9\u05dd \u05d1\u05e6\u05d5\u05e8\u05d4 \u05d8\u05d1\u05e2\u05d9\u05ea \u05d5\u05d9\u05d4\u05e4\u05d5\u05da \u05e8\u05d5\u05d8\u05d9\u05e0\u05d5\u05ea \u05db\u05ea\u05d5\u05d1\u05d5\u05ea \u05dc\u05d4\u05d5\u05e8\u05d0\u05d5\u05ea \u05e7\u05d5\u05dc\u05d9\u05d5\u05ea \u05e9\u05d9\u05de\u05d5\u05e9\u05d9\u05d5\u05ea. \u05d1\u05d0\u05d5\u05ea\u05d4 \u05e8\u05d5\u05d7 \u05d0\u05e0\u05d9 \u05d0\u05d5\u05d4\u05d1\u05ea \u05d2\u05dd \u05e1\u05e4\u05e8\u05d9 \u05d0\u05d5\u05d3\u05d9\u05d5, \u05e4\u05d5\u05d3\u05e7\u05d0\u05e1\u05d8\u05d9\u05dd \u05d5\u05e7\u05e8\u05d9\u05d0\u05ea \u05e1\u05e4\u05e8\u05d9\u05dd, \u05d1\u05de\u05d9\u05d5\u05d7\u05d3 \u05e1\u05e4\u05e8\u05d9 \u05d1\u05dc\u05e9, \u05de\u05e1\u05ea\u05d5\u05e8\u05d9\u05df, \u05e8\u05d5\u05de\u05e0\u05d9\u05dd \u05e4\u05e1\u05d9\u05db\u05d5\u05dc\u05d5\u05d2\u05d9\u05d9\u05dd \u05d5\u05e7\u05dc\u05d0\u05e1\u05d9\u05e7\u05d5\u05ea \u05d7\u05db\u05de\u05d5\u05ea \u05e9\u05de\u05ea\u05d2\u05de\u05dc\u05d5\u05ea \u05ea\u05e9\u05d5\u05de\u05ea \u05dc\u05d1 \u05d5\u05d7\u05e9\u05d9\u05d1\u05d4 \u05d1\u05e9\u05db\u05d1\u05d5\u05ea.")
